namespace sv_df177eb6eb2b40a38eba53f9cb7cf6ec.Models;

public record JobApplication(PersonalInfo Personal, WorkHistory Work, List<Reference> References, string CoverLetter);
public record PersonalInfo(string FullName, string Email, string Phone, string Address);
public record WorkHistory(List<WorkEntry> Entries);
public record WorkEntry(string Company, string Title, DateTime StartDate, DateTime? EndDate, string Description);
public record Reference(string Name, string Relationship, string Email, string Phone);

public interface IApplicationService
{
    Task<int> SubmitApplicationAsync(JobApplication application);
    Task<bool> ValidateEmailAsync(string email);
}

@page "/apply"
@rendermode InteractiveServer
@using sv_df177eb6eb2b40a38eba53f9cb7cf6ec.Models
@inject IApplicationService ApplicationService

<PageTitle>Job Application</PageTitle>

<div class="container py-4" style="max-width: 800px;">
    <h2 class="mb-4">Job Application</h2>

    @* ───── Step Indicator Bar ───── *@
    <nav class="d-flex justify-content-between mb-4 position-relative">
        <div class="position-absolute" style="top:18px;left:10%;right:10%;height:2px;background:#dee2e6;z-index:0;"></div>
        @for (int i = 0; i < _stepNames.Length; i++)
        {
            var step = i;
            var isCompleted = step < _currentStep;
            var isCurrent = step == _currentStep;
            <div class="text-center position-relative" style="z-index:1;flex:1;">
                <button type="button"
                        class="btn rounded-circle d-inline-flex align-items-center justify-content-center @(isCurrent ? "btn-primary" : isCompleted ? "btn-success" : "btn-outline-secondary")"
                        style="width:36px;height:36px;font-size:.85rem;"
                        disabled="@(!isCompleted && !isCurrent)"
                        @onclick="() => GoToStep(step)">
                    @if (isCompleted)
                    {
                        <span>✓</span>
                    }
                    else
                    {
                        <span>@(step + 1)</span>
                    }
                </button>
                <div class="small mt-1 @(isCurrent ? "fw-bold" : isCompleted ? "text-success" : "text-muted")">
                    @_stepNames[step]
                </div>
            </div>
        }
    </nav>

    @if (!string.IsNullOrEmpty(_errorMessage))
    {
        <div class="alert alert-danger">@_errorMessage</div>
    }

    @if (_submitted)
    {
        @* ───── Confirmation ───── *@
        <div class="text-center py-5">
            <div class="text-success mb-3" style="font-size:4rem;">✓</div>
            <h3>Application Submitted!</h3>
            <p class="text-muted">Your application ID is <strong>@_applicationId</strong>.</p>
        </div>
    }
    else
    {
        @* ───── Step 1: Personal Info ───── *@
        @if (_currentStep == 0)
        {
            <h4>Personal Information</h4>
            <div class="mb-3">
                <label class="form-label">Full Name <span class="text-danger">*</span></label>
                <input class="form-control" @bind="_fullName" />
            </div>
            <div class="mb-3">
                <label class="form-label">Email <span class="text-danger">*</span></label>
                <input type="email" class="form-control" @bind="_email" />
            </div>
            <div class="mb-3">
                <label class="form-label">Phone <span class="text-danger">*</span></label>
                <input type="tel" class="form-control" @bind="_phone" />
            </div>
            <div class="mb-3">
                <label class="form-label">Address <span class="text-danger">*</span></label>
                <textarea class="form-control" rows="2" @bind="_address"></textarea>
            </div>
            <div class="d-flex justify-content-end">
                <button class="btn btn-primary" @onclick="NextStep" disabled="@_isProcessing">
                    @if (_isProcessing) { <span class="spinner-border spinner-border-sm me-1"></span> }
                    Next
                </button>
            </div>
        }

        @* ───── Step 2: Work History ───── *@
        @if (_currentStep == 1)
        {
            <h4>Work History</h4>
            @for (int i = 0; i < _workEntries.Count; i++)
            {
                var idx = i;
                var entry = _workEntries[idx];
                <div class="card mb-3">
                    <div class="card-body">
                        <div class="d-flex justify-content-between align-items-center mb-2">
                            <h6 class="mb-0">Position @(idx + 1)</h6>
                            @if (_workEntries.Count > 1)
                            {
                                <button class="btn btn-sm btn-outline-danger" @onclick="() => RemoveWorkEntry(idx)">Remove</button>
                            }
                        </div>
                        <div class="mb-2">
                            <label class="form-label">Company <span class="text-danger">*</span></label>
                            <input class="form-control" @bind="entry.Company" />
                        </div>
                        <div class="mb-2">
                            <label class="form-label">Job Title <span class="text-danger">*</span></label>
                            <input class="form-control" @bind="entry.Title" />
                        </div>
                        <div class="row mb-2">
                            <div class="col-md-6">
                                <label class="form-label">Start Date <span class="text-danger">*</span></label>
                                <input type="date" class="form-control" @bind="entry.StartDate" />
                            </div>
                            <div class="col-md-6">
                                <label class="form-label">End Date</label>
                                <input type="date" class="form-control" @bind="entry.EndDate" disabled="@entry.IsCurrent" />
                                <div class="form-check mt-1">
                                    <input type="checkbox" class="form-check-input" id="@($"current-{idx}")" @bind="entry.IsCurrent" />
                                    <label class="form-check-label" for="@($"current-{idx}")">Currently working here</label>
                                </div>
                            </div>
                        </div>
                        <div class="mb-2">
                            <label class="form-label">Description</label>
                            <textarea class="form-control" rows="2" @bind="entry.Description"></textarea>
                        </div>
                    </div>
                </div>
            }
            <button class="btn btn-outline-secondary mb-3" @onclick="AddWorkEntry">+ Add Another Position</button>
            <div class="d-flex justify-content-between">
                <button class="btn btn-secondary" @onclick="PrevStep">Back</button>
                <button class="btn btn-primary" @onclick="NextStep">Next</button>
            </div>
        }

        @* ───── Step 3: References ───── *@
        @if (_currentStep == 2)
        {
            <h4>References</h4>
            @for (int i = 0; i < _references.Count; i++)
            {
                var idx = i;
                var r = _references[idx];
                <div class="card mb-3">
                    <div class="card-body">
                        <div class="d-flex justify-content-between align-items-center mb-2">
                            <h6 class="mb-0">Reference @(idx + 1)</h6>
                            @if (_references.Count > 2)
                            {
                                <button class="btn btn-sm btn-outline-danger" @onclick="() => RemoveReference(idx)">Remove</button>
                            }
                        </div>
                        <div class="mb-2">
                            <label class="form-label">Name <span class="text-danger">*</span></label>
                            <input class="form-control" @bind="r.Name" />
                        </div>
                        <div class="mb-2">
                            <label class="form-label">Relationship <span class="text-danger">*</span></label>
                            <input class="form-control" @bind="r.Relationship" />
                        </div>
                        <div class="row mb-2">
                            <div class="col-md-6">
                                <label class="form-label">Email <span class="text-danger">*</span></label>
                                <input type="email" class="form-control" @bind="r.Email" />
                            </div>
                            <div class="col-md-6">
                                <label class="form-label">Phone <span class="text-danger">*</span></label>
                                <input type="tel" class="form-control" @bind="r.Phone" />
                            </div>
                        </div>
                    </div>
                </div>
            }
            @if (_references.Count < 3)
            {
                <button class="btn btn-outline-secondary mb-3" @onclick="AddReference">+ Add Reference</button>
            }
            <div class="d-flex justify-content-between">
                <button class="btn btn-secondary" @onclick="PrevStep">Back</button>
                <button class="btn btn-primary" @onclick="NextStep">Next</button>
            </div>
        }

        @* ───── Step 4: Cover Letter ───── *@
        @if (_currentStep == 3)
        {
            <h4>Cover Letter</h4>
            <div class="mb-2">
                <textarea class="form-control" rows="10" maxlength="2000" @bind="_coverLetter" @bind:event="oninput"></textarea>
            </div>
            <div class="text-muted small mb-3">@(_coverLetter?.Length ?? 0) / 2000 characters</div>
            <div class="d-flex justify-content-between">
                <button class="btn btn-secondary" @onclick="PrevStep">Back</button>
                <button class="btn btn-primary" @onclick="NextStep">Next</button>
            </div>
        }

        @* ───── Step 5: Review & Submit ───── *@
        @if (_currentStep == 4)
        {
            <h4>Review &amp; Submit</h4>

            <div class="card mb-3">
                <div class="card-header d-flex justify-content-between align-items-center">
                    <strong>Personal Information</strong>
                    <button class="btn btn-sm btn-link" @onclick="() => GoToStep(0)">Edit</button>
                </div>
                <div class="card-body">
                    <dl class="row mb-0">
                        <dt class="col-sm-3">Name</dt><dd class="col-sm-9">@_fullName</dd>
                        <dt class="col-sm-3">Email</dt><dd class="col-sm-9">@_email</dd>
                        <dt class="col-sm-3">Phone</dt><dd class="col-sm-9">@_phone</dd>
                        <dt class="col-sm-3">Address</dt><dd class="col-sm-9">@_address</dd>
                    </dl>
                </div>
            </div>

            <div class="card mb-3">
                <div class="card-header d-flex justify-content-between align-items-center">
                    <strong>Work History</strong>
                    <button class="btn btn-sm btn-link" @onclick="() => GoToStep(1)">Edit</button>
                </div>
                <div class="card-body">
                    @foreach (var entry in _workEntries)
                    {
                        <div class="mb-3">
                            <strong>@entry.Title</strong> at @entry.Company<br />
                            <span class="text-muted">
                                @entry.StartDate.ToString("MMM yyyy") –
                                @(entry.IsCurrent ? "Present" : entry.EndDate?.ToString("MMM yyyy"))
                            </span>
                            @if (!string.IsNullOrWhiteSpace(entry.Description))
                            {
                                <p class="mt-1 mb-0">@entry.Description</p>
                            }
                        </div>
                    }
                </div>
            </div>

            <div class="card mb-3">
                <div class="card-header d-flex justify-content-between align-items-center">
                    <strong>References</strong>
                    <button class="btn btn-sm btn-link" @onclick="() => GoToStep(2)">Edit</button>
                </div>
                <div class="card-body">
                    @foreach (var r in _references)
                    {
                        <div class="mb-2">
                            <strong>@r.Name</strong> — @r.Relationship<br />
                            <span class="text-muted">@r.Email · @r.Phone</span>
                        </div>
                    }
                </div>
            </div>

            <div class="card mb-3">
                <div class="card-header d-flex justify-content-between align-items-center">
                    <strong>Cover Letter</strong>
                    <button class="btn btn-sm btn-link" @onclick="() => GoToStep(3)">Edit</button>
                </div>
                <div class="card-body">
                    <p style="white-space:pre-wrap;">@_coverLetter</p>
                </div>
            </div>

            <div class="d-flex justify-content-between">
                <button class="btn btn-secondary" @onclick="PrevStep">Back</button>
                <button class="btn btn-success" @onclick="SubmitApplication" disabled="@_isProcessing">
                    @if (_isProcessing) { <span class="spinner-border spinner-border-sm me-1"></span> }
                    Submit Application
                </button>
            </div>
        }
    }
</div>

